class Solution(object):
    def minOperations(self, nums1, nums2):
        n = len(nums1)
        INF = float('inf')

        def count_ops(a_last, b_last):
            ops = 0
            for i in range(n - 1):
                a, b = nums1[i], nums2[i]
                if a <= a_last and b <= b_last:
                    pass
                elif a <= b_last and b <= a_last:
                    ops += 1
                else:
                    return INF
            return ops

        res1 = count_ops(nums1[n-1], nums2[n-1])
        res2 = count_ops(nums2[n-1], nums1[n-1])
        if res2 != INF:
            res2 += 1
        ans = min(res1, res2)
        return ans if ans != INF else -1
